INSERT OR REPLACE INTO pages(slug,page_type,title,meta_description,eyebrow,h1,direct_answer,intro,content_json,faq_json,source_links_json,primary_keyword,cluster,search_intent,status,featured,source_checked_at,published_at) VALUES(
'esim-come-funziona','guide','eSIM: come funziona, vantaggi e limiti | Senza Roaming','Come funziona una eSIM, cosa serve per installarla e quali controlli fare prima del viaggio.','Guida essenziale','eSIM: come funziona davvero','Una eSIM è un profilo SIM digitale scaricato su un dispositivo compatibile. Servono un telefono abilitato, un piano e una connessione Internet durante l’installazione. Il momento in cui parte la validità dipende dal piano e deve essere controllato prima dell’attivazione.','Puoi preparare la connessione prima della partenza e, quando il dispositivo lo permette, mantenere attiva anche la SIM principale.','[{"type":"heading","text":"Cosa succede dopo l’acquisto"},{"type":"steps","items":["Scegli il piano.","Ricevi QR code o installazione guidata.","Scarichi il profilo con Internet.","Imposti la eSIM per i dati mobili.","Segui le regole di attivazione del provider."]},{"type":"heading","text":"Controlli essenziali"},{"type":"bullets","items":["Modello esatto compatibile.","Telefono sbloccato.","Inizio della validità.","Hotspot, velocità e fair use."]},{"type":"callout","title":"Attenzione all’attivazione","text":"Alcuni piani iniziano all’installazione, altri alla prima connessione nella destinazione."}]','[{"question":"Serve Internet per installare una eSIM?","answer":"In genere sì, perché il profilo deve essere scaricato."},{"question":"La eSIM sostituisce la SIM fisica?","answer":"Può sostituirla o affiancarla, in base al telefono e al numero di linee supportate."}]','[{"label":"GSMA — eSIM","url":"https://www.gsma.com/solutions-and-impact/technologies/esim/"},{"label":"Airalo Help","url":"https://www.airalo.com/help"},{"label":"Holafly FAQ","url":"https://esim.holafly.com/faq/"}]','esim come funziona','Fondamentali','informational','published',1,'2026-07-16','2026-07-16');

INSERT OR REPLACE INTO pages(slug,page_type,title,meta_description,eyebrow,h1,direct_answer,intro,content_json,faq_json,source_links_json,primary_keyword,cluster,search_intent,status,featured,source_checked_at,published_at) VALUES(
'migliore-esim','comparison','Migliore eSIM per viaggiare: come scegliere | Senza Roaming','Confronta destinazione, dati, durata, hotspot, rete, attivazione e prezzo prima di scegliere una eSIM.','Confronto indipendente','La migliore eSIM dipende dal viaggio','Non esiste una eSIM migliore per tutti. La scelta corretta copre l’intero itinerario, dura abbastanza, funziona sul tuo telefono e include dati, hotspot e velocità adatti all’uso previsto. Il prezzo va confrontato soltanto dopo questi controlli.','La pagina espone il metodo di confronto; le raccomandazioni numeriche verranno pubblicate solo con dati commerciali verificati e datati.','[{"type":"heading","text":"Criteri di confronto"},{"type":"table","headers":["Criterio","Controllo"],"rows":[["Destinazione","Tutti i Paesi sono inclusi?"],["Durata","Copre tutti i giorni?"],["Dati","GB reali o fair use?"],["Hotspot","È consentito?"],["Attivazione","Quando parte la validità?"],["Rete","Quali reti e velocità?"],["Prezzo","Valuta, imposte e condizioni?"]]},{"type":"callout","title":"Niente classifiche finte","text":"Una graduatoria viene pubblicata soltanto dopo aver verificato i piani disponibili."}]','[{"question":"Airalo o Holafly: quale scegliere?","answer":"Dipende dal piano disponibile per la destinazione, dai dati, dal fair use, dall’hotspot, dalla durata e dal prezzo verificato."},{"question":"La eSIM più economica è sempre migliore?","answer":"No. Può durare meno, includere meno dati o avere limitazioni inadatte al viaggio."}]','[{"label":"GSMA — eSIM","url":"https://www.gsma.com/solutions-and-impact/technologies/esim/"},{"label":"Airalo Help","url":"https://www.airalo.com/help"},{"label":"Holafly FAQ","url":"https://esim.holafly.com/faq/"}]','migliore esim','Confronti','commercial','published',1,'2026-07-16','2026-07-16');

INSERT OR REPLACE INTO pages(slug,page_type,title,meta_description,eyebrow,h1,direct_answer,intro,content_json,faq_json,source_links_json,primary_keyword,cluster,search_intent,status,featured,source_checked_at,published_at) VALUES(
'esim-estero','guide','eSIM per l’estero: guida alla scelta | Senza Roaming','Scegli una eSIM per l’estero controllando itinerario, giorni, dati, hotspot e attivazione.','Prima della partenza','Come scegliere una eSIM per l’estero','Parti dall’itinerario: conta i giorni, verifica tutti i Paesi attraversati, stima il consumo dati e decidi se servono hotspot, chiamate o soltanto Internet. Installa il profilo prima della partenza quando possibile, ma attivalo secondo le regole del piano.','Piani locali, regionali e globali possono sembrare simili, ma copertura, durata e limiti cambiano.','[{"type":"heading","text":"Locale, regionale o globale"},{"type":"table","headers":["Tipo","Quando può convenire"],"rows":[["Locale","Un solo Paese."],["Regionale","Più Paesi della stessa area."],["Globale","Itinerari ampi o viaggi frequenti."]]},{"type":"heading","text":"Checklist"},{"type":"bullets","items":["Telefono compatibile e sbloccato.","Durata sufficiente.","Paesi inclusi.","Hotspot e fair use.","Istruzioni salvate offline.","Assistenza disponibile."]}]','[{"question":"Conviene comprarla prima di partire?","answer":"Di solito sì, ma bisogna controllare quando inizia la validità."},{"question":"Una sola eSIM può coprire più Paesi?","answer":"Sì, se il piano regionale o globale include esplicitamente l’intero itinerario."}]','[{"label":"GSMA — eSIM","url":"https://www.gsma.com/solutions-and-impact/technologies/esim/"},{"label":"Airalo Help","url":"https://www.airalo.com/help"},{"label":"Holafly FAQ","url":"https://esim.holafly.com/faq/"}]','esim estero','Viaggio','commercial','published',1,'2026-07-16','2026-07-16');

INSERT OR REPLACE INTO pages(slug,page_type,title,meta_description,eyebrow,h1,direct_answer,intro,content_json,faq_json,source_links_json,primary_keyword,cluster,search_intent,status,featured,source_checked_at,published_at) VALUES(
'esim-telefoni-compatibili','guide','Telefoni compatibili con eSIM: come verificare | Senza Roaming','Verifica se il modello esatto di iPhone, Samsung, Xiaomi o Android supporta eSIM.','Compatibilità','Come verificare se un telefono supporta eSIM','La compatibilità può cambiare in base a modello, variante, Paese di vendita e operatore. Il controllo più sicuro è cercare nel dispositivo la funzione per aggiungere una eSIM e confrontare il codice modello con la documentazione ufficiale del produttore.','Le liste generiche sono utili, ma non sostituiscono il controllo del modello esatto e dello stato di blocco dell’operatore.','[{"type":"heading","text":"Controllo rapido"},{"type":"steps","items":["Apri le impostazioni della rete mobile.","Cerca Aggiungi eSIM o Aggiungi piano cellulare.","Identifica il codice modello.","Controlla la documentazione ufficiale del produttore.","Verifica che il telefono sia sbloccato."]},{"type":"callout","title":"Modelli importati","text":"Un telefono acquistato in un altro mercato può avere caratteristiche diverse pur usando lo stesso nome commerciale."}]','[{"question":"Tutti gli iPhone supportano eSIM?","answer":"No. La compatibilità dipende dal modello e dal mercato di vendita."},{"question":"Un telefono compatibile può essere bloccato?","answer":"Sì. Il supporto tecnico alla eSIM non garantisce che il dispositivo accetti piani di altri operatori."}]','[{"label":"GSMA — eSIM","url":"https://www.gsma.com/solutions-and-impact/technologies/esim/"}]','telefoni con esim','Compatibilità','informational','published',1,'2026-07-16','2026-07-16');
